#include <bits/stdc++.h>
using namespace std;

int main() {
    string s;
    char c;
    cin >> s >> c;
    // ここにコードを書いてください
    return 0;
}

hint:
文字列を 1 文字ずつ見て、c と一致したら数えます。

```cpp
int count = 0;
for (char ch : s) if (ch == c) count++;
cout << count << endl;
```

explanation:
## 解説

`cin >> s >> c` で文字列と 1 文字を読みます（`>>` は空白を読み飛ばすので改行も自動でスキップされます）。一致する文字を数えます。

```cpp
int count = 0;
for (char ch : s) if (ch == c) count++;
cout << count << endl;
```

answer_code:
#include <bits/stdc++.h>
using namespace std;

int main() {
    string s;
    char c;
    cin >> s >> c;
    int count = 0;
    for (char ch : s) if (ch == c) count++;
    cout << count << endl;
    return 0;
}
